  1	import * as React from 'react';
  2	import NamespaceSafetyBox from '@odf/core/components/utils/safety-box';
  3	import { useNodesData } from '@odf/core/hooks';
  4	import { NodeData } from '@odf/core/types';
  5	import { getStorageClassDescription } from '@odf/core/utils';
  6	import { getCephNodes } from '@odf/ocs/utils/common';
  7	import { SingleSelectDropdown } from '@odf/shared';
  8	import { OCS_OPERATOR, ROOK_CEPH_OPERATOR } from '@odf/shared/constants';
  9	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
 10	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
 11	import { LoadingInline } from '@odf/shared/generic/Loading';
 12	import {
 13	  useCustomPrometheusPoll,
 14	  usePrometheusBasePath,
 15	} from '@odf/shared/hooks/custom-prometheus-poll';
 16	import { StorageClusterActionModalProps } from '@odf/shared/modals/common';
 17	import { ModalBody, ModalFooter, ModalHeader } from '@odf/shared/modals/Modal';
 18	import { DeploymentModel, StorageClusterModel } from '@odf/shared/models';
 19	import { PersistentVolumeModel, StorageClassModel } from '@odf/shared/models';
 20	import { getName, getNamespace } from '@odf/shared/selectors';
 21	import {
 22	  StorageClassResourceKind,
 23	  StorageClusterKind,
 24	  DeviceSet,
 25	  DeploymentKind,
 26	} from '@odf/shared/types';
 27	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 28	import {
 29	  getStorageSizeInTiBWithoutUnit,
 30	  humanizeBinaryBytes,
 31	  referenceForModel,
 32	} from '@odf/shared/utils';
 33	import {
 34	  useK8sWatchResource,
 35	  WatchK8sResource,
 36	  k8sPatch,
 37	  PrometheusEndpoint,
 38	} from '@openshift-console/dynamic-plugin-sdk';
 39	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk-internal/lib/extensions/console-types';
 40	import classNames from 'classnames';
 41	import { TFunction } from 'react-i18next';
 42	import { Trans } from 'react-i18next';
 43	import { compose } from 'redux';
 44	import {
 45	  FormGroup,
 46	  TextInput,
 47	  TextContent,
 48	  Button,
 49	  Modal,
 50	  Alert,
 51	  ModalVariant,
 52	  SelectOption,
 53	} from '@patternfly/react-core';
 54	import {
 55	  createWizardNodeState,
 56	  getDeviceSetReplica,
 57	} from '../../components/utils';
 58	import {
 59	  DefaultRequestSize,
 60	  deviceClassTooltip,
 61	  NO_PROVISIONER,
 62	  requestedCapacityTooltip,
 63	  storageClassTooltip,
 64	} from '../../constants';
 65	import { CAPACITY_INFO_QUERIES, StorageDashboardQuery } from '../../queries';
 66	import {
 67	  checkArbiterCluster,
 68	  checkFlexibleScaling,
 69	  createDeviceSet,
 70	  filterSC,
 71	  getCurrentDeviceSetIndex,
 72	  getDeviceSetCount,
 73	  getRequestedPVCSize,
 74	  getSCAvailablePVs,
 75	  isArbiterSC,
 76	  isValidTopology,
 77	} from '../../utils/ocs';
 78	import { PVsAvailableCapacity } from './pvs-available-capacity';
 79	import './add-capacity-modal.scss';
 80	
 81	type StorageClassDropdownProps = {
 82	  onChange: any;
 83	  'data-test': string;
 84	  initialSelection: (args) => any;
 85	  filter: (resource: StorageClassResourceKind) => StorageClassResourceKind;
 86	};
 87	
 88	type DeviceClassDropdownProps = {
 89	  deviceClasses: string[];
 90	  selectedDeviceClass: string;
 91	  onChange: (deviceClass: string) => void;
 92	  'data-test'?: string;
 93	  placeholder?: string;
 94	  className?: string;
 95	};
 96	
 97	export const StorageClassDropdown: React.FC<StorageClassDropdownProps> = ({
 98	  onChange,
 99	  'data-test': dataTest,
100	  initialSelection,
101	  filter,
102	}) => {
103	  return (
104	    <ResourceDropdown<StorageClassResourceKind>
105	      resource={scResource}
106	      resourceModel={StorageClassModel}
107	      showBadge
108	      secondaryTextGenerator={getStorageClassDescription}
109	      onSelect={onChange}
110	      initialSelection={initialSelection}
111	      filterResource={compose(filterSC, filter)}
112	      data-test={dataTest}
113	    />
114	  );
115	};
116	
117	export const DeviceClassDropdown: React.FC<DeviceClassDropdownProps> = ({
118	  deviceClasses,
119	  selectedDeviceClass,
120	  onChange,
121	  'data-test': dataTest,
122	}) => {
123	  const { t } = useCustomTranslation();
124	
125	  const deviceClassOptions = deviceClasses.map((cls) => (
126	    <SelectOption key={cls} value={cls}>
127	      {cls}
128	    </SelectOption>
129	  ));
130	
131	  return (
132	    <SingleSelectDropdown
133	      id="device-class"
134	      selectOptions={deviceClassOptions}
135	      selectedKey={selectedDeviceClass}
136	      onChange={onChange}
137	      placeholderText={t('Select device class')}
138	      className="ceph-add-capacity__device-class-dropdown"
139	      data-test={dataTest}
140	    />
141	  );
142	};
143	
144	const useVerifyStorageClusterExpansionIsPossbile = (
145	  storageCluster: StorageClusterKind
146	): boolean => {
147	  const clusterNamespace = getNamespace(storageCluster);
148	  const deploymentResource: WatchK8sResource = {
149	    kind: DeploymentModel.kind,
150	    namespaced: true,
151	    isList: true,
152	    namespace: clusterNamespace,
153	  };
154	  const [deployments, isLoaded, loadError] =
155	    useK8sWatchResource<DeploymentKind[]>(deploymentResource);
156	  const isRookCephOperatorPresent =
157	    isLoaded &&
158	    !loadError &&
159	    deployments?.find(
160	      (deployment) => getName(deployment) === ROOK_CEPH_OPERATOR
161	    )?.status.replicas > 0;
162	  const isOCSOperatorPresent =
163	    isLoaded &&
164	    !loadError &&
165	    deployments?.find((deployment) => getName(deployment) === OCS_OPERATOR)
166	      ?.status.replicas > 0;
167	  if (!isLoaded || loadError) {
168	    return false;
169	  }
170	  return isRookCephOperatorPresent && isOCSOperatorPresent;
171	};
172	
173	const scResource: WatchK8sResource = {
174	  kind: StorageClassModel.kind,
175	  namespaced: false,
176	  isList: true,
177	};
178	
179	const pvResource: WatchK8sResource = {
180	  kind: PersistentVolumeModel.kind,
181	  namespaced: false,
182	  isList: true,
183	};
184	
185	const getProvisionedCapacity = (value: number, replica: number) =>
186	  Number.isInteger(value * replica)
187	    ? value * replica
188	    : (value * replica).toFixed(2);
189	
190	const RawCapacity: React.FC<RawCapacityProps> = ({
191	  t,
192	  osdSizeWithoutUnit,
193	  replica,
194	}) => {
195	  const provisionedCapacity = getProvisionedCapacity(
196	    osdSizeWithoutUnit,
197	    replica
198	  );
199	  return (
200	    <FormGroup
201	      fieldId="request-size"
202	      label={t('Raw Capacity')}
203	      labelHelp={<FieldLevelHelp>{requestedCapacityTooltip(t)}</FieldLevelHelp>}
204	    >
205	      <div className="pf-v6-u-display-flex pf-v6-u-pt-sm pf-v6-u-pl-xs">
206	        <TextInput
207	          isDisabled
208	          id="request-size"
209	          className={classNames(
210	            'pf-v6-c-form-control',
211	            'ceph-add-capacity__input'
212	          )}
213	          type="number"
214	          name="requestSize"
215	          value={osdSizeWithoutUnit}
216	          aria-label="requestSize"
217	          data-test="requestSize"
218	        />
219	        <TextContent className="ceph-add-capacity__provisioned-capacity pf-v6-u-ml-xs">
220	          {' '}
221	          {t('x {{ replica, number }} replicas =', {
222	            replica,
223	          })}{' '}
224	          <strong data-test="provisioned-capacity">
225	            {provisionedCapacity}&nbsp;TiB
226	          </strong>
227	        </TextContent>
228	      </div>
229	    </FormGroup>
230	  );
231	};
232	
233	const getDeviceClassesForSC = (
234	  deviceSets: DeviceSet[],
235	  scName: string
236	): string[] =>
237	  deviceSets
238	    .filter((ds) => ds.dataPVCTemplate?.spec?.storageClassName === scName)
239	    .map((ds) => ds.deviceClass);
240	
241	type RawCapacityProps = {
242	  osdSizeWithoutUnit: number;
243	  replica: number;
244	  t: TFunction;
245	};
246	
247	const AddCapacityModal: React.FC<StorageClusterActionModalProps> = ({
248	  extraProps: { storageCluster: actionStorageCluster },
249	  closeModal,
250	  isOpen,
251	}) => {
252	  const { t } = useCustomTranslation();
253	  const isExpansionPossible =
254	    useVerifyStorageClusterExpansionIsPossbile(actionStorageCluster);
255	
256	  const ocsClusterNs = getNamespace(actionStorageCluster);
257	  const ocsClusterName = getName(actionStorageCluster);
258	  const [storageCluster] = useK8sWatchResource<StorageClusterKind>({
259	    kind: referenceForModel(StorageClusterModel),
260	    name: ocsClusterName,
261	    namespace: ocsClusterNs,
262	  });
263	  const [cephTotal, totalError, totalLoading] = useCustomPrometheusPoll({
264	    endpoint: 'api/v1/query' as PrometheusEndpoint,
265	    query:
266	      CAPACITY_INFO_QUERIES(ocsClusterName)[
267	        StorageDashboardQuery.RAW_CAPACITY_TOTAL
268	      ],
269	    basePath: usePrometheusBasePath(),
270	  });
271	  const [cephUsed, usedError, usedLoading] = useCustomPrometheusPoll({
272	    endpoint: 'api/v1/query' as PrometheusEndpoint,
273	    query:
274	      CAPACITY_INFO_QUERIES(ocsClusterName)[
275	        StorageDashboardQuery.RAW_CAPACITY_USED
276	      ],
277	    basePath: usePrometheusBasePath(),
278	  });
279	  const [values, loading, loadError] = [
280	    [
281	      cephTotal?.data?.result?.[0]?.value?.[1],
282	      cephUsed?.data?.result?.[0]?.value?.[1],
283	    ],
284	    totalLoading || usedLoading,
285	    totalError || usedError,
286	  ];
287	  const [pvData, pvLoaded, pvLoadError] =
288	    useK8sWatchResource<K8sResourceCommon[]>(pvResource);
289	  const [nodesData, nodesLoaded, nodesLoadError] = useNodesData();
290	  const [scResources, scResourcesLoaded, scResourcesLoadError] =
291	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
292	  const [storageClass, setStorageClass] = React.useState(null);
293	  const [deviceClass, setDeviceClass] = React.useState('');
294	  const [inProgress, setProgress] = React.useState(false);
295	  const [errorMessage, setError] = React.useState('');
296	
297	  const deviceSets = storageCluster?.spec?.storageDeviceSets || [];
298	  const osdSizeWithUnit = getRequestedPVCSize(deviceSets?.[0]?.dataPVCTemplate);
299	  const osdSizeWithoutUnit = getStorageSizeInTiBWithoutUnit(osdSizeWithUnit);
300	  const isNoProvionerSC: boolean = storageClass?.provisioner === NO_PROVISIONER;
301	  const selectedSCName: string = getName(storageClass);
302	
303	  const hasFlexibleScaling = checkFlexibleScaling(storageCluster);
304	  const isArbiterEnabled: boolean = checkArbiterCluster(storageCluster);
305	  const replica = getDeviceSetReplica(
306	    isArbiterEnabled,
307	    hasFlexibleScaling,
308	    createWizardNodeState(getCephNodes(nodesData, ocsClusterNs) as NodeData[])
309	  );
310	
311	  const totalCapacityMetric = values?.[0];
312	  const usedCapacityMetric = values?.[1];
313	  const usedCapacity = humanizeBinaryBytes(usedCapacityMetric);
314	  const totalCapacity = humanizeBinaryBytes(totalCapacityMetric);
315	  /** Name of the installation storageClass which will be the pre-selected value for the dropdown */
316	  const installStorageClass =
317	    deviceSets?.[0]?.dataPVCTemplate?.spec?.storageClassName;
318	  const nodesError: boolean =
319	    nodesLoadError || !(nodesData as []).length || !nodesLoaded;
320	
321	  const preSelectionFilter = React.useCallback(
322	    (storageClasses: StorageClassResourceKind[]) =>
323	      storageClasses.find((sc) => getName(sc) === installStorageClass),
324	    [installStorageClass]
325	  );
326	
327	  const deviceClasses = getDeviceClassesForSC(deviceSets, selectedSCName);
328	
329	  const hasMultiDeviceClasses = deviceClasses.length > 1;
330	
331	  const deviceSetIndex: number = getCurrentDeviceSetIndex(
332	    deviceSets,
333	    selectedSCName,
334	    hasMultiDeviceClasses ? deviceClass : null
335	  );
336	
337	  // Stops users from moving from no-prov SC to prov SC. (Bug 2213183)
338	  const storageClassFilter = React.useCallback(
339	    (sc: StorageClassResourceKind) => {
340	      if (scResourcesLoaded && !scResourcesLoadError) {
341	        const initialSC = scResources?.find(
342	          (item) => getName(item) === installStorageClass
343	        );
344	        if (initialSC?.provisioner === NO_PROVISIONER) {
345	          return sc.provisioner === NO_PROVISIONER ? sc : undefined;
346	        }
347	      }
348	      return sc;
349	    },
350	    [installStorageClass, scResources, scResourcesLoadError, scResourcesLoaded]
351	  );
352	
353	  const validateSC = React.useCallback(() => {
354	    if (!selectedSCName) return t('No StorageClass selected');
355	    if (!isNoProvionerSC || hasFlexibleScaling) return '';
356	    if (isArbiterEnabled && !isArbiterSC(selectedSCName, pvData, nodesData)) {
357	      return t(
358	        'The Arbiter stretch cluster requires a minimum of 4 nodes (2 different zones, 2 nodes per zone). Please choose a different StorageClass or create a new LocalVolumeSet that matches the minimum node requirement.'
359	      );
360	    }
361	    if (
362	      !isArbiterEnabled &&
363	      !isValidTopology(selectedSCName, pvData, nodesData)
364	    ) {
365	      return t(
366	        'The StorageCluster requires a minimum of 3 nodes. Please choose a different StorageClass or create a new LocalVolumeSet that matches the minimum node requirement.'
367	      );
368	    }
369	    return '';
370	  }, [
371	    selectedSCName,
372	    t,
373	    isNoProvionerSC,
374	    isArbiterEnabled,
375	    hasFlexibleScaling,
376	    pvData,
377	    nodesData,
378	  ]);
379	
380	  let currentCapacity: React.ReactNode;
381	  let availablePvsCount: number = 0;
382	
383	  if (!pvLoadError && pvData.length && pvLoaded) {
384	    const pvs: K8sResourceCommon[] = getSCAvailablePVs(pvData, selectedSCName);
385	    availablePvsCount = pvs.length;
386	  }
387	
388	  if (loading) {
389	    currentCapacity = (
390	      <div className="skeleton-text ceph-add-capacity__current-capacity--loading" />
391	    );
392	  } else if (loadError || !totalCapacityMetric || !usedCapacityMetric) {
393	    currentCapacity = <div className="text-muted">{t('Not available')}</div>;
394	  } else {
395	    currentCapacity = (
396	      <div className="text-muted">
397	        <strong>{`${usedCapacity.string} / ${totalCapacity.string}`}</strong>
398	      </div>
399	    );
400	  }
401	
402	  const submit = (event: React.FormEvent<EventTarget>) => {
403	    event.preventDefault();
404	    setProgress(true);
405	    const patch = {
406	      op: '',
407	      path: '',
408	      value: null,
409	    };
410	    const osdSizeRequest = isNoProvionerSC
411	      ? DefaultRequestSize.BAREMETAL
412	      : osdSizeWithUnit;
413	    let portable = !isNoProvionerSC;
414	    let deviceSetReplica = replica;
415	    let deviceSetCount = 1;
416	
417	    if (hasFlexibleScaling) {
418	      portable = false;
419	    }
420	    if (isNoProvionerSC)
421	      deviceSetCount = getDeviceSetCount(availablePvsCount, deviceSetReplica);
422	
423	    if (deviceSetIndex === -1) {
424	      patch.op = 'add';
425	      patch.path = `/spec/storageDeviceSets/-`;
426	      patch.value = createDeviceSet(
427	        selectedSCName,
428	        osdSizeRequest,
429	        portable,
430	        deviceSetReplica,
431	        deviceSetCount
432	      );
433	    } else {
434	      patch.op = 'replace';
435	      patch.path = `/spec/storageDeviceSets/${deviceSetIndex}/count`;
436	      patch.value = deviceSets[deviceSetIndex].count + deviceSetCount;
437	    }
438	
439	    const validation: string = validateSC();
440	    if (validation) {
441	      setError(validation);
442	      setProgress(false);
443	    } else {
444	      k8sPatch({
445	        model: StorageClusterModel,
446	        resource: storageCluster,
447	        data: [patch],
448	      })
449	        .then(() => {
450	          setProgress(false);
451	          closeModal();
452	        })
453	        .catch((err) => {
454	          setError(err);
455	          setProgress(false);
456	        });
457	    }
458	  };
459	  const Header = <ModalHeader>{t('Add Capacity')}</ModalHeader>;
460	  return (
461	    <Modal
462	      header={Header}
463	      isOpen={isOpen}
464	      onClose={closeModal}
465	      showClose={false}
466	      hasNoBodyWrapper={true}
467	      variant={ModalVariant.small}
468	      className="add-capacity-modal"
469	      aria-label="Add Capacity"
470	    >
471	      <NamespaceSafetyBox>
472	        <ModalBody className="add-capacity-modal--overflow">
473	          <Trans
474	            t={t as any}
475	            ns="plugin__odf-console"
476	            values={{ ocsClusterName }}
477	          >
478	            Adding capacity for <strong>{{ ocsClusterName }}</strong>, may
479	            increase your expenses.
480	          </Trans>
481	          <FormGroup
482	            className="pf-v6-u-pt-md pf-v6-u-pb-sm"
483	            id="add-cap-sc-dropdown__FormGroup"
484	            fieldId="add-capacity-dropdown"
485	            label={t('StorageClass')}
486	            labelHelp={
487	              <FieldLevelHelp>{storageClassTooltip(t)}</FieldLevelHelp>
488	            }
489	            isRequired
490	          >
491	            <div
492	              id="add-capacity-dropdown"
493	              className="ceph-add-capacity__sc-dropdown"
494	            >
495	              <StorageClassDropdown
496	                onChange={(sc: StorageClassResourceKind) => setStorageClass(sc)}
497	                data-test="add-cap-sc-dropdown"
498	                initialSelection={preSelectionFilter}
499	                filter={storageClassFilter}
500	              />
501	            </div>
502	            {!selectedSCName && (
503	              <div className="skeleton-text ceph-add-capacity__storage-class-dropdown--loading" />
504	            )}
505	          </FormGroup>
506	          {hasMultiDeviceClasses && (
507	            <FormGroup
508	              className="pf-v6-u-pt-md pf-v6-u-pb-sm"
509	              label={t('Device class')}
510	              fieldId="device-class"
511	              labelHelp={
512	                <FieldLevelHelp>{deviceClassTooltip(t)}</FieldLevelHelp>
513	              }
514	            >
515	              <DeviceClassDropdown
516	                deviceClasses={deviceClasses}
517	                selectedDeviceClass={deviceClass}
518	                onChange={setDeviceClass}
519	                data-test="add-cap-dc-dropdown"
520	              />
521	            </FormGroup>
522	          )}
523	
524	          {!!selectedSCName &&
525	            (isNoProvionerSC ? (
526	              <PVsAvailableCapacity
527	                replica={replica}
528	                data-test-id="ceph-add-capacity-pvs-available-capacity"
529	                storageClass={storageClass}
530	                data={pvData}
531	                loaded={pvLoaded}
532	                loadError={pvLoadError}
533	              />
534	            ) : (
535	              <>
536	                {!!osdSizeWithoutUnit && (
537	                  <RawCapacity
538	                    t={t}
539	                    replica={replica}
540	                    osdSizeWithoutUnit={osdSizeWithoutUnit}
541	                  />
542	                )}
543	                <TextContent className="ceph-add-capacity__current-capacity pf-v6-u-mt-sm">
544	                  {t('Currently Used:')}&nbsp;
545	                  {currentCapacity}
546	                </TextContent>
547	              </>
548	            ))}
549	          {errorMessage && (
550	            <Alert isInline variant="danger" title={t('An error occurred')}>
551	              {(errorMessage as any)?.message || errorMessage}
552	            </Alert>
553	          )}
554	          {!isExpansionPossible && (
555	            <Alert
556	              isInline
557	              variant="danger"
558	              title={t('Add Capacity cannot proceed')}
559	            >
560	              {t(
561	                'The "Add Capacity" operation cannot proceed because one or more essential operators (rook-ceph or ocs-operator) are not running or scaled down. Ensure these operators are active and try again.'
562	              )}
563	            </Alert>
564	          )}
565	        </ModalBody>
566	        <ModalFooter>
567	          <Button
568	            key="cancel"
569	            variant="secondary"
570	            onClick={closeModal}
571	            data-test-id="modal-cancel-action"
572	          >
573	            {t('Cancel')}
574	          </Button>
575	          {!loading || !inProgress ? (
576	            <Button
577	              key="Add"
578	              data-test="modal-submit-action"
579	              data-test-id="confirm-action"
580	              variant="primary"
581	              onClick={submit}
582	              isDisabled={
583	                (isNoProvionerSC && (!availablePvsCount || nodesError)) ||
584	                !isExpansionPossible ||
585	                (hasMultiDeviceClasses && !deviceClass)
586	              }
587	            >
588	              {t('Add')}
589	            </Button>
590	          ) : (
591	            <LoadingInline />
592	          )}
593	        </ModalFooter>
594	      </NamespaceSafetyBox>
595	    </Modal>
596	  );
597	};
598	
599	export default AddCapacityModal;

