144	const useVerifyStorageClusterExpansionIsPossbile = (
145	  storageCluster: StorageClusterKind
146	): boolean => {
147	  const clusterNamespace = getNamespace(storageCluster);
148	  const deploymentResource: WatchK8sResource = {
149	    kind: DeploymentModel.kind,
150	    namespaced: true,
151	    isList: true,
152	    namespace: clusterNamespace,
153	  };
154	  const [deployments, isLoaded, loadError] =
155	    useK8sWatchResource<DeploymentKind[]>(deploymentResource);
156	  const isRookCephOperatorPresent =
157	    isLoaded &&
158	    !loadError &&
159	    deployments?.find(
160	      (deployment) => getName(deployment) === ROOK_CEPH_OPERATOR
161	    )?.status.replicas > 0;
162	  const isOCSOperatorPresent =
163	    isLoaded &&
164	    !loadError &&
165	    deployments?.find((deployment) => getName(deployment) === OCS_OPERATOR)
166	      ?.status.replicas > 0;
167	  if (!isLoaded || loadError) {
168	    return false;
169	  }
170	  return isRookCephOperatorPresent && isOCSOperatorPresent;
171	};
