173	const scResource: WatchK8sResource = {
174	  kind: StorageClassModel.kind,
175	  namespaced: false,
176	  isList: true,
177	};
178	
179	const pvResource: WatchK8sResource = {
180	  kind: PersistentVolumeModel.kind,
181	  namespaced: false,
182	  isList: true,
183	};
