203	      labelHelp={<FieldLevelHelp>{requestedCapacityTooltip(t)}</FieldLevelHelp>}
204	    >
205	      <div className="pf-v6-u-display-flex pf-v6-u-pt-sm pf-v6-u-pl-xs">
206	        <TextInput
207	          isDisabled
208	          id="request-size"
209	          className={classNames(
210	            'pf-v6-c-form-control',
211	            'ceph-add-capacity__input'
212	          )}
213	          type="number"
214	          name="requestSize"
215	          value={osdSizeWithoutUnit}
216	          aria-label="requestSize"
217	          data-test="requestSize"
218	        />
219	        <Content className="ceph-add-capacity__provisioned-capacity pf-v6-u-ml-xs">
220	          {' '}
221	          {t('x {{ replica, number }} replicas =', {
222	            replica,
223	          })}{' '}
224	          <strong data-test="provisioned-capacity">
225	            {provisionedCapacity}&nbsp;TiB
226	          </strong>
227	        </Content>
228	      </div>
229	    </FormGroup>
230	  );
231	};
232	
233	const getDeviceClassesForSC = (
234	  deviceSets: DeviceSet[],
235	  scName: string
236	): string[] =>
237	  deviceSets
238	    .filter((ds) => ds.dataPVCTemplate?.spec?.storageClassName === scName)
239	    .map((ds) => ds.deviceClass);
240	
241	type RawCapacityProps = {
242	  osdSizeWithoutUnit: number;
243	  replica: number;
244	  t: TFunction;
245	};
246	
247	const AddCapacityModal: React.FC<StorageClusterActionModalProps> = ({
248	  extraProps: { storageCluster: actionStorageCluster },
249	  closeModal,
250	  isOpen,
251	}) => {
252	  const { t } = useCustomTranslation();
253	  const isExpansionPossible =
254	    useVerifyStorageClusterExpansionIsPossbile(actionStorageCluster);
255	
256	  const ocsClusterNs = getNamespace(actionStorageCluster);
257	  const ocsClusterName = getName(actionStorageCluster);
258	  const [storageCluster] = useK8sWatchResource<StorageClusterKind>({
259	    kind: referenceForModel(StorageClusterModel),
260	    name: ocsClusterName,
261	    namespace: ocsClusterNs,
262	  });
263	  const [cephTotal, totalError, totalLoading] = useCustomPrometheusPoll({
264	    endpoint: 'api/v1/query' as PrometheusEndpoint,
265	    query:
266	      CAPACITY_INFO_QUERIES(ocsClusterName)[
267	        StorageDashboardQuery.RAW_CAPACITY_TOTAL
268	      ],
269	    basePath: usePrometheusBasePath(),
270	  });
271	  const [cephUsed, usedError, usedLoading] = useCustomPrometheusPoll({
272	    endpoint: 'api/v1/query' as PrometheusEndpoint,
273	    query:
274	      CAPACITY_INFO_QUERIES(ocsClusterName)[
275	        StorageDashboardQuery.RAW_CAPACITY_USED
276	      ],
277	    basePath: usePrometheusBasePath(),
278	  });
279	  const [values, loading, loadError] = [
280	    [
281	      cephTotal?.data?.result?.[0]?.value?.[1],
282	      cephUsed?.data?.result?.[0]?.value?.[1],
283	    ],
284	    totalLoading || usedLoading,
285	    totalError || usedError,
286	  ];
287	  const [pvData, pvLoaded, pvLoadError] =
288	    useK8sWatchResource<K8sResourceCommon[]>(pvResource);
289	  const [nodesData, nodesLoaded, nodesLoadError] = useNodesData();
290	  const [scResources, scResourcesLoaded, scResourcesLoadError] =
291	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
292	  const [storageClass, setStorageClass] = React.useState(null);
293	  const [deviceClass, setDeviceClass] = React.useState('');
294	  const [inProgress, setProgress] = React.useState(false);
295	  const [errorMessage, setError] = React.useState('');
296	
297	  const deviceSets = storageCluster?.spec?.storageDeviceSets || [];
298	  const osdSizeWithUnit = getRequestedPVCSize(deviceSets?.[0]?.dataPVCTemplate);
299	  const osdSizeWithoutUnit = getStorageSizeInTiBWithoutUnit(osdSizeWithUnit);
300	  const isNoProvionerSC: boolean = storageClass?.provisioner === NO_PROVISIONER;
301	  const selectedSCName: string = getName(storageClass);
302	
303	  const hasFlexibleScaling = checkFlexibleScaling(storageCluster);
304	  const isArbiterEnabled: boolean = checkArbiterCluster(storageCluster);
305	  const replica = getDeviceSetReplica(
306	    isArbiterEnabled,
307	    hasFlexibleScaling,
308	    createWizardNodeState(getCephNodes(nodesData, ocsClusterNs) as NodeData[])
309	  );
310	
311	  const totalCapacityMetric = values?.[0];
312	  const usedCapacityMetric = values?.[1];
313	  const usedCapacity = humanizeBinaryBytes(usedCapacityMetric);
314	  const totalCapacity = humanizeBinaryBytes(totalCapacityMetric);
315	  /** Name of the installation storageClass which will be the pre-selected value for the dropdown */
316	  const installStorageClass =
317	    deviceSets?.[0]?.dataPVCTemplate?.spec?.storageClassName;
318	  const nodesError: boolean =
319	    nodesLoadError || !(nodesData as []).length || !nodesLoaded;
320	
321	  const preSelectionFilter = React.useCallback(
322	    (storageClasses: StorageClassResourceKind[]) =>
323	      storageClasses.find((sc) => getName(sc) === installStorageClass),
324	    [installStorageClass]
325	  );
326	
327	  const deviceClasses = getDeviceClassesForSC(deviceSets, selectedSCName);
328	
329	  const hasMultiDeviceClasses = deviceClasses.length > 1;
330	
331	  const deviceSetIndex: number = getCurrentDeviceSetIndex(
332	    deviceSets,
333	    selectedSCName,
334	    hasMultiDeviceClasses ? deviceClass : null
335	  );
336	
337	  // Stops users from moving from no-prov SC to prov SC. (Bug 2213183)
338	  const storageClassFilter = React.useCallback(
339	    (sc: StorageClassResourceKind) => {
340	      if (scResourcesLoaded && !scResourcesLoadError) {
341	        const initialSC = scResources?.find(
342	          (item) => getName(item) === installStorageClass
343	        );
344	        if (initialSC?.provisioner === NO_PROVISIONER) {
345	          return sc.provisioner === NO_PROVISIONER ? sc : undefined;
346	        }
347	      }
348	      return sc;
349	    },
350	    [installStorageClass, scResources, scResourcesLoadError, scResourcesLoaded]
351	  );
352	
353	  const validateSC = React.useCallback(() => {
354	    if (!selectedSCName) return t('No StorageClass selected');
355	    if (!isNoProvionerSC || hasFlexibleScaling) return '';
356	    if (isArbiterEnabled && !isArbiterSC(selectedSCName, pvData, nodesData)) {
357	      return t(
358	        'The Arbiter stretch cluster requires a minimum of 4 nodes (2 different zones, 2 nodes per zone). Please choose a different StorageClass or create a new LocalVolumeSet that matches the minimum node requirement.'
359	      );
360	    }
361	    if (
362	      !isArbiterEnabled &&
363	      !isValidTopology(selectedSCName, pvData, nodesData)
364	    ) {
365	      return t(
366	        'The StorageCluster requires a minimum of 3 nodes. Please choose a different StorageClass or create a new LocalVolumeSet that matches the minimum node requirement.'
367	      );
368	    }
369	    return '';
370	  }, [
371	    selectedSCName,
372	    t,
373	    isNoProvionerSC,
374	    isArbiterEnabled,
375	    hasFlexibleScaling,
376	    pvData,
377	    nodesData,
378	  ]);
379	
380	  let currentCapacity: React.ReactNode;
381	  let availablePvsCount: number = 0;
382	
383	  if (!pvLoadError && pvData.length && pvLoaded) {
384	    const pvs: K8sResourceCommon[] = getSCAvailablePVs(pvData, selectedSCName);
385	    availablePvsCount = pvs.length;
386	  }
387	
388	  if (loading) {
389	    currentCapacity = (
390	      <div className="skeleton-text ceph-add-capacity__current-capacity--loading" />
391	    );
392	  } else if (loadError || !totalCapacityMetric || !usedCapacityMetric) {
393	    currentCapacity = <div className="text-muted">{t('Not available')}</div>;
394	  } else {
395	    currentCapacity = (
396	      <div className="text-muted">
397	        <strong>{`${usedCapacity.string} / ${totalCapacity.string}`}</strong>
398	      </div>
399	    );
400	  }
401	
402	  const submit = (event: React.FormEvent<EventTarget>) => {
403	    event.preventDefault();
404	    setProgress(true);
405	    const patch = {
406	      op: '',
407	      path: '',
408	      value: null,
409	    };
410	    const osdSizeRequest = isNoProvionerSC
411	      ? DefaultRequestSize.BAREMETAL
412	      : osdSizeWithUnit;
413	    let portable = !isNoProvionerSC;
414	    let deviceSetReplica = replica;
415	    let deviceSetCount = 1;
416	
417	    if (hasFlexibleScaling) {
418	      portable = false;
419	    }
420	    if (isNoProvionerSC)
421	      deviceSetCount = getDeviceSetCount(availablePvsCount, deviceSetReplica);
422	
423	    if (deviceSetIndex === -1) {
424	      patch.op = 'add';
425	      patch.path = `/spec/storageDeviceSets/-`;
426	      patch.value = createDeviceSet(
427	        selectedSCName,
428	        osdSizeRequest,
429	        portable,
430	        deviceSetReplica,
431	        deviceSetCount
432	      );
433	    } else {
434	      patch.op = 'replace';
435	      patch.path = `/spec/storageDeviceSets/${deviceSetIndex}/count`;
436	      patch.value = deviceSets[deviceSetIndex].count + deviceSetCount;
437	    }
438	
439	    const validation: string = validateSC();
440	    if (validation) {
441	      setError(validation);
442	      setProgress(false);
443	    } else {
444	      k8sPatch({
445	        model: StorageClusterModel,
446	        resource: storageCluster,
447	        data: [patch],
448	      })
449	        .then(() => {
450	          setProgress(false);
451	          closeModal();
452	        })
453	        .catch((err) => {
454	          setError(err);
455	          setProgress(false);
456	        });
457	    }
458	  };
459	  const Header = <ModalHeader>{t('Add Capacity')}</ModalHeader>;
460	  return (
461	    <Modal
462	      isOpen={isOpen}
463	      onClose={closeModal}
464	      variant={ModalVariant.small}
465	      className="add-capacity-modal"
466	      aria-label="Add Capacity"
467	    >
468	      {Header}
469	      <NamespaceSafetyBox>
470	        <ModalBody className="add-capacity-modal--overflow">
471	          <Trans
472	            t={t as any}
473	            ns="plugin__odf-console"
474	            values={{ ocsClusterName }}
475	          >
476	            Adding capacity for <strong>{{ ocsClusterName }}</strong>, may
477	            increase your expenses.
478	          </Trans>
479	          <FormGroup
480	            className="pf-v6-u-pt-md pf-v6-u-pb-sm"
481	            id="add-cap-sc-dropdown__FormGroup"
482	            fieldId="add-capacity-dropdown"
483	            label={t('StorageClass')}
484	            labelHelp={
485	              <FieldLevelHelp>{storageClassTooltip(t)}</FieldLevelHelp>
486	            }
487	            isRequired
488	          >
489	            <div
490	              id="add-capacity-dropdown"
491	              className="ceph-add-capacity__sc-dropdown"
492	            >
493	              <StorageClassDropdown
494	                onChange={(sc: StorageClassResourceKind) => setStorageClass(sc)}
495	                data-test="add-cap-sc-dropdown"
496	                initialSelection={preSelectionFilter}
497	                filter={storageClassFilter}
498	              />
499	            </div>
500	            {!selectedSCName && (
501	              <div className="skeleton-text ceph-add-capacity__storage-class-dropdown--loading" />
502	            )}
503	          </FormGroup>
504	          {hasMultiDeviceClasses && (
505	            <FormGroup
506	              className="pf-v6-u-pt-md pf-v6-u-pb-sm"
507	              label={t('Device class')}
508	              fieldId="device-class"
509	              labelHelp={
510	                <FieldLevelHelp>{deviceClassTooltip(t)}</FieldLevelHelp>
511	              }
512	            >
513	              <DeviceClassDropdown
514	                deviceClasses={deviceClasses}
515	                selectedDeviceClass={deviceClass}
516	                onChange={setDeviceClass}
517	                data-test="add-cap-dc-dropdown"
518	              />
519	            </FormGroup>
520	          )}
521	
522	          {!!selectedSCName &&
523	            (isNoProvionerSC ? (
524	              <PVsAvailableCapacity
525	                replica={replica}
526	                data-test-id="ceph-add-capacity-pvs-available-capacity"
527	                storageClass={storageClass}
528	                data={pvData}
529	                loaded={pvLoaded}
530	                loadError={pvLoadError}
531	              />
532	            ) : (
533	              <>
534	                {!!osdSizeWithoutUnit && (
535	                  <RawCapacity
536	                    t={t}
537	                    replica={replica}
538	                    osdSizeWithoutUnit={osdSizeWithoutUnit}
539	                  />
540	                )}
541	                <Content className="ceph-add-capacity__current-capacity pf-v6-u-mt-sm">
542	                  {t('Currently Used:')}&nbsp;
543	                  {currentCapacity}
544	                </Content>
545	              </>
546	            ))}
547	          {errorMessage && (
548	            <Alert isInline variant="danger" title={t('An error occurred')}>
549	              {(errorMessage as any)?.message || errorMessage}
550	            </Alert>
551	          )}
552	          {!isExpansionPossible && (
553	            <Alert
554	              isInline
555	              variant="danger"
556	              title={t('Add Capacity cannot proceed')}
557	            >
558	              {t(
559	                'The "Add Capacity" operation cannot proceed because one or more essential operators (rook-ceph or ocs-operator) are not running or scaled down. Ensure these operators are active and try again.'
560	              )}
561	            </Alert>
562	          )}
563	        </ModalBody>
564	        <ModalFooter>
565	          <Button
566	            key="cancel"
567	            variant="secondary"
568	            onClick={closeModal}
569	            data-test-id="modal-cancel-action"
570	          >
571	            {t('Cancel')}
572	          </Button>
573	          {!loading || !inProgress ? (
574	            <Button
575	              key="Add"
576	              data-test="modal-submit-action"
577	              data-test-id="confirm-action"
578	              variant="primary"
579	              onClick={submit}
580	              isDisabled={
581	                (isNoProvionerSC && (!availablePvsCount || nodesError)) ||
582	                !isExpansionPossible ||
583	                (hasMultiDeviceClasses && !deviceClass)
584	              }
585	            >
586	              {t('Add')}
587	            </Button>
588	          ) : (
589	            <LoadingInline />
590	          )}
591	        </ModalFooter>
592	      </NamespaceSafetyBox>
593	    </Modal>
594	  );
595	};
